module top_module(
    input [3:0] in,
    input [1:0] sel,
    input clk,
    input rst,
    output reg out
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst or posedge dbg_halt) begin
    if (rst == 1'b0) begin
        out <= 1'b0;
    end else begin
        case (sel)
            2'b00: out <= in[0];
            2'b01: out <= in[1];
            2'b10: out <= in[2];
            2'b11: out <= in[3];
        endcase
    end
end

endmodule
